LAYER
	NAME "provincias"
	TYPE polygon	
	STATUS on
	DATA "geom FROM (SELECT * FROM ign.provincias) as kaypacha using unique gid using srid=4326"
	INCLUDE "configuracion/postgresql_kaypacha.map"
	CLASSITEM "gid"
	PROJECTION
	"init=epsg:4326"
	END
	METADATA
		"layer_encoding" "Latin1"
		"wfs_encoding" "Latin1"
		"queryable" "true"
		"wfs_abstract" "Provincias || Instituto Geográfico Nacional :: Perú"
		"wfs_title" "Provincias"
		"wfs_credit" "IGN"
		"wfs_srs" "EPSG:4326"
		"gml_include_items" "all"
		"gml_featureid" "gid"
		"wfs_getfeature_formatlist" "OGRGML,SHAPE-ZIP,CSV,geojson"
		#"wfs_additional_files_in_output" "lotes.pdf,lotes.lyr"
	END
	CLASS
		NAME "Provincia"
		STYLE
			COLOR -1 -1 -1
			OUTLINECOLOR -1 -1 -1
			WIDTH 1
		END
	END
END # Layer